  CREATE TABLE "TREXONE_DATA"."EPCS_AUDIT"
   (	"LOG_TYPE" CHAR(1),
	"LOG_PRIORITY" NUMBER(1,0),
	"LOG_MESSAGE" VARCHAR2(4000),
	"PPI_MESSAGE_ID_VALUE" VARCHAR2(35),
	"PPI_MESSAGE_SENDER_VALUE" VARCHAR2(80),
	"PPI_MESSAGE_SENDER_QUAL" VARCHAR2(3),
	"DATA_GROUP" NUMBER(18,0),
	"SYS_USER" NUMBER(18,0),
	"ERX_CLIENT_ID" VARCHAR2(100) DEFAULT sys_context('ERX_CONTEXT','ERX_CLIENT_ID') NOT NULL ENABLE,
	"EVENT_OUTCOME" CHAR(1),
	"EVENT_CATEGORY" VARCHAR2(255),
	"EVENT_SUB_CATEGORY" VARCHAR2(255),
	"EPCS_PRES_FIRST_NAME" VARCHAR2(35),
	"EPCS_PRES_LAST_NAME" VARCHAR2(35),
	"EPCS_PRES_DEA_NUMBER" VARCHAR2(35),
	"SUBJECT_LOGIN_NAME" VARCHAR2(255),
	"EXECUTING_LOGIN_NAME" VARCHAR2(255),
	"RX_NUMBER" VARCHAR2(30),
	"NUM_UPDATES" NUMBER(9,0) DEFAULT 0,
	"DATESTAMP" DATE DEFAULT TO_DATE(TO_CHAR(SYS_EXTRACT_UTC(SYSTIMESTAMP),'YYYYMMDDHH24MISS'),'YYYYMMDDHH24MISS') NOT NULL ENABLE NOVALIDATE,
	"EXTENDED_TIMESTAMP" TIMESTAMP (6) DEFAULT SYS_EXTRACT_UTC(SYSTIMESTAMP),
	"EVENT_DATESTAMP" DATE DEFAULT sysdate,
	 CONSTRAINT "CC_EPCS_AUDIT_01" CHECK (LOG_TYPE in ('I','A')) ENABLE,
	 CONSTRAINT "CC_EPCS_AUDIT_02" CHECK (LOG_PRIORITY in (1,2,3)) ENABLE,
	 CONSTRAINT "CC_EPCS_AUDIT_03" CHECK (EVENT_OUTCOME in ('S','F')) ENABLE
   )
  PARTITION BY RANGE ("DATESTAMP") INTERVAL (NUMTOYMINTERVAL(3,'MONTH')) STORE IN ("LARGE_DATA01")
